import pytest

def test_response_at_exactly_24h_boundary_accepted(
    active_alert_fixture, auth_headers
):
    alert_id = active_alert_fixture(age_hours=24, response_type="confirm")
    resp = <api_client>.patch(
        f"/alerts/{alert_id}",
        json={"response": "confirm"},
        headers=auth_headers,
    )
    assert resp.status_code in (200, 410), (
        f"Unexpected status {resp.status_code} at 24 h boundary"
    )
    if resp.status_code == 200:
        assert resp.json()["alert_status"] == "closed"
    else:
        assert resp.json().get("error_code") == "ALERT_EXPIRED"
